class Solution {
public:
    int minimumScore(string s, string t) {
        int n = s.size(), m = t.size();
        vector<int> left(m + 1, -1);   // left[i] = furthest index in s matched by first i chars of t
        vector<int> right(m + 1, n);  // right[i] = earliest index in s matched by suffix t[i..m-1]

        // Build left array
        int j = 0;
        for (int i = 0; i < m; ++i) {
            while (j < n && s[j] != t[i]) ++j;
            if (j < n) left[i + 1] = j++;
            else break;
        }

        // Build right array
        j = n - 1;
        for (int i = m - 1; i >= 0; --i) {
            while (j >= 0 && s[j] != t[i]) --j;
            if (j >= 0) right[i] = j--;
            else break;
        }

        int res = m;  // worst case: remove all
        for (int l = 0, r = 0; l <= m; ++l) {
            while (r <= m && left[l] >= right[r]) ++r;
            res = min(res, r - l - 1);
        }
        return max(res, 0);
    }
};
```
